const PokemonData* findPokemonData(const std::string& name)
{
    for (int i = 0; i < POKEMON_COUNT; ++i)
    {
        if (name == POKEMON_LIST[i].name)
        {
            return &POKEMON_LIST[i];
        }
    }

    return nullptr;
}

